begin;

create temporary table deep_exam_modules (module_key text primary key, exam_title text not null, slug_candidates text[] not null, title_patterns text[] not null) on commit drop;
insert into deep_exam_modules values
  ('module-01', 'Program Design and Periodisering - Toets', array['training-periodisation', 'program-design-and-periodisering', 'program-design-periodisering', 'training-and-periodisation', 'program-design']::text[], array['%training%period%', '%program design%period%', '%program%periodisering%']::text[]),
  ('module-02', 'Nutrition - Toets', array['nutrition-plan-design', 'nutrition']::text[], array['%nutrition%']::text[]),
  ('module-03', 'How to Start and Standout - Toets', array['start-stand-out-as-coach', 'how-to-start-and-standout', 'start-and-standout']::text[], array['%start%stand%', '%start%out%']::text[]),
  ('module-04', 'Leadership and Coaching Skills - Toets', array['leadership-coaching-skills', 'leadership-and-coaching-skills']::text[], array['%leadership%coaching%']::text[]),
  ('module-05', 'Scale Your Service - Toets', array['scale-your-service', 'scaling-your-service']::text[], array['%scale%service%', '%scaling%service%']::text[]);

create temporary table deep_exam_targets on commit drop as
select distinct on (seed.module_key) seed.module_key, seed.exam_title, module.id as module_id
from deep_exam_modules seed
join lateral (
  select id, order_index from public.modules
  where lower(slug) = any(seed.slug_candidates) or lower(title) like any(seed.title_patterns)
  order by order_index, id limit 1
) module on true
order by seed.module_key, module.order_index, module.id;

do $$ declare missing text; begin
  select string_agg(module_key, ', ' order by module_key) into missing from deep_exam_modules
  where module_key not in (select module_key from deep_exam_targets);
  if missing is not null then raise exception 'Modules niet gevonden: %', missing; end if;
end $$;

insert into public.exams (module_id, title, description, passing_score, is_published)
select module_id, exam_title, 'Beantwoord 10 vragen die begrip, toepassing en analyse van deze module toetsen.', 70, true
from deep_exam_targets
on conflict (module_id) do update set title = excluded.title, description = excluded.description, is_published = true, updated_at = now();

create temporary table deep_exam_bank (module_key text not null, order_index integer not null, question_text text not null, options jsonb not null, correct_answer text not null, explanation text not null, primary key(module_key, order_index)) on commit drop;
insert into deep_exam_bank values
  ('module-01', 1, 'Een coach kiest eerst de trainingsfrequentie en pas daarna de split. Welke redenering volgt de module?', jsonb_build_array('De split bepaalt hoeveel vrije dagen en vaste herstelblokken de cliënt in de volledige trainingsweek moet maken.', 'De realistisch haalbare weekfrequentie bepaalt welke spierverdeling uitvoerbaar is.', 'De gekozen compounds bepalen automatisch hoeveel sessies iemand nodig heeft.', 'De duur van de macrocyclus bepaalt hoeveel dagen iemand wekelijks traint.'), 'De realistisch haalbare weekfrequentie bepaalt welke spierverdeling uitvoerbaar is.', 'Frequentie is het aantal krachttrainingen per week en vormt de basis voor een haalbare split in de context van de general population. Bron: learning-objectives.md LO1; concepts.md ‘Frequentie’ en ‘Trainingssplit’; 00:00-01:42.'),
  ('module-01', 2, 'Welke beschrijving geeft de verhouding tussen macro- en mesocyclus het nauwkeurigst weer?', jsonb_build_array('Een macrocyclus beschrijft één volledige sessie; een mesocyclus omvat vervolgens de volledige trainingsloopbaan van de cliënt.', 'Beide cycli hebben dezelfde duur, maar gebruiken andere oefeningen.', 'Een mesocyclus bepaalt de weeksplit; een macrocyclus bepaalt de sessievolgorde.', 'Een macrocyclus draagt het overkoepelende doel en bevat kortere mesocycli met gerichte prikkels.'), 'Een macrocyclus draagt het overkoepelende doel en bevat kortere mesocycli met gerichte prikkels.', 'De module gebruikt een macrocyclus van ongeveer twaalf weken, opgebouwd uit kortere mesocycli waarin volume en load bewust kunnen veranderen. Bron: learning-objectives.md LO5; concepts.md ‘Macrocyclus’, ‘Mesocyclus’ en ‘Volume- en loadfase’; 31:02-35:50.'),
  ('module-01', 3, 'Een cliënt kan twee keer per week trainen en is vrij op maandag, dinsdag en donderdag. Welke planning sluit het best aan bij de module?', jsonb_build_array('Full body op maandag en donderdag, met herstel tussen beide sessies.', 'Full body op maandag en dinsdag, zodat de trainingsprikkel gebundeld is.', 'Upper op maandag en opnieuw upper op dinsdag, zonder lowersessie.', 'Lower op dinsdag en isolatie op donderdag, zonder uppersessie.'), 'Full body op maandag en donderdag, met herstel tussen beide sessies.', 'Bij twee trainingsdagen past een full-bodystructuur, met bij voorkeur ongeveer 48 uur tussen de sessies; maandag en donderdag respecteert beide principes. Bron: lessons.md les 1-2; source-map.md ‘Frequentie en doelgroep’ en ‘Splits kiezen’; 00:00-06:09.'),
  ('module-01', 4, 'Een cliënt kan vier dagen trainen en wil elke hoofdregio herhaald belasten. Welke basisstructuur past het best?', jsonb_build_array('Vier full-bodysessies achter elkaar, met telkens dezelfde compounds.', 'Upper, upper, lower, lower, zonder rekening te houden met herstel.', 'Upper 1, lower 1, herstel, upper 2, lower 2.', 'Eén full body, gevolgd door drie sessies met alleen isolatie.'), 'Upper 1, lower 1, herstel, upper 2, lower 2.', 'De module koppelt vier trainingsdagen aan een upper/lowerstructuur waarin beide regio’s terugkomen en herstel in de week wordt ingebouwd. Bron: lessons.md les 2 en 4-5; 02:36-06:09 en 12:01-28:09.'),
  ('module-01', 5, 'Een coach combineert een upper- en lowerblueprint tot één full-bodysessie met beperkte tijd. Welke aanpassing volgt de module?', jsonb_build_array('De compounds uit beide blueprints schrappen en alleen de kortere isolatiereeksen voor upper en lower behouden.', 'De compounds uit upper en lower behouden en de onderste isolatiereeksen weglaten.', 'Alle oefeningen behouden en uitsluitend de rusttijden halveren.', 'Alle loweroefeningen schrappen en de volledige upperreeks behouden.'), 'De compounds uit upper en lower behouden en de onderste isolatiereeksen weglaten.', 'Bij de combinatie naar full body blijven de compounds uit upper en lower de kern; de onderste C-reeksen met isolatie vallen weg. Bron: lessons.md les 6 ‘Full body combineren’; 28:09-33:53.'),
  ('module-01', 6, 'Een beginnende cliënt kan de barpositie van een front squat nog niet comfortabel aannemen. Welke keuze past bij het voorbeeld uit de module?', jsonb_build_array('De squatbeweging volledig vervangen door een armisolatie.', 'De front squat behouden en de techniekproblemen negeren.', 'De oefening uitstellen tot de cliënt een gevorderd schema volgt.', 'Een goblet squat gebruiken als toegankelijkere squatvariant.'), 'Een goblet squat gebruiken als toegankelijkere squatvariant.', 'De module noemt de goblet squat toegankelijker voor starters wanneer de barpositie van de front squat een beperking vormt. Bron: lessons.md les 3, praktisch voorbeeld; 06:09-12:01.'),
  ('module-01', 7, 'Een coach geeft een zware compound en een isolatieoefening exact dezelfde lage rep range en loadlogica. Welke correctie sluit aan bij de module?', jsonb_build_array('De compound zwaarder en lager in reps programmeren, en isolatie niet automatisch dezelfde logica geven.', 'Beide oefeningen lichter maken en de rep range verder gelijk houden.', 'De isolatie zwaarder maken dan de compound om de sessie te balanceren.', 'Rep ranges verwijderen en alleen het aantal oefeningen noteren.'), 'De compound zwaarder en lager in reps programmeren, en isolatie niet automatisch dezelfde logica geven.', 'De module koppelt lagere reps aan zwaardere belasting bij compounds en waarschuwt dat isolatie niet dezelfde rep- en intensiteitslogica krijgt. Bron: learning-objectives.md LO4; concepts.md ‘Rep range en intensiteit’; 20:40-21:01.'),
  ('module-01', 8, 'Een cliënt die normaal vier dagen traint, kan door een reis alleen maandag en dinsdag trainen. De coach plant twee identieke full-bodysessies. Wat is de belangrijkste afwijking van de module?', jsonb_build_array('De coach gebruikt te weinig verschillende isolatieoefeningen in beide sessies.', 'De coach verandert tijdelijk de normale trainingsfrequentie van de cliënt.', 'De coach belast hetzelfde volledige lichaam opnieuw zonder de aanbevolen herstelruimte.', 'De coach gebruikt twee sessies binnen één kalenderweek.'), 'De coach belast hetzelfde volledige lichaam opnieuw zonder de aanbevolen herstelruimte.', 'De module noemt twee full-bodysessies op opeenvolgende dagen onlogisch doordat herstel van de eerste sessie de tweede beïnvloedt. Bron: lessons.md les 1-2, praktisch reisvoorbeeld; 00:00-06:09.'),
  ('module-01', 9, 'Een coach vervangt elke week alle compounds om plateaus te voorkomen. Welke beoordeling past het best bij de module?', jsonb_build_array('Juist, want oefenherhaling verhindert elke nieuwe trainingsprikkel.', 'Juist, zolang de isolatieoefeningen gedurende twaalf weken gelijk blijven.', 'Onjuist, omdat alleen extra trainingsdagen een plateau kunnen doorbreken.', 'Onjuist, omdat oefeningen voldoende consistent moeten blijven terwijl prikkel en intensiteit over fasen veranderen.'), 'Onjuist, omdat oefeningen voldoende consistent moeten blijven terwijl prikkel en intensiteit over fasen veranderen.', 'De module zoekt consistentie in oefeningen, noemt ongeveer zes weken als bruikbare periode en varieert de prikkel via periodisering in plaats van wekelijkse willekeur. Bron: lessons.md les 7 ‘Periodisering, cycli en intensiteit’; 33:53-46:39.'),
  ('module-01', 10, 'Een twaalfwekenprogramma gebruikt elke week dezelfde oefeningen, sets, reps en gemiddelde intensiteit. Resultaten vlakken af. Wat is volgens de module de meest gerichte ingreep?', jsonb_build_array('De volledige trainingssplit wekelijks willekeurig maken.', 'De macrocyclus opdelen in mesocycli waarin volume en load bewust stijgen en dalen.', 'Alle assistance-oefeningen definitief verwijderen uit iedere sessie.', 'De trainingsfrequentie verhogen zonder de belastingsopbouw te wijzigen.'), 'De macrocyclus opdelen in mesocycli waarin volume en load bewust stijgen en dalen.', 'Periodisering maakt het lange plan dynamisch door kortere fasen met verschillende volume- en loadprikkels binnen hetzelfde overkoepelende doel. Bron: learning-objectives.md LO5; concepts.md ‘Periodisering’ en ‘Volume- en loadfase’; 31:02-46:39.'),
  ('module-02', 1, 'Welke situatie is een voorbeeld van NEAT en niet van geplande training, BMR of TEF?', jsonb_build_array('Na iedere maaltijd extra energie gebruiken om het opgenomen voedsel te verteren en verder te verwerken.', 'Een geplande krachttraining van zestig minuten uitvoeren.', 'Doorheen de werkdag extra stappen zetten en vaker de trap nemen.', 'In rust energie gebruiken voor de basisfuncties van het lichaam.'), 'Doorheen de werkdag extra stappen zetten en vaker de trap nemen.', 'NEAT is dagelijkse beweging buiten sport, zoals stappen, fietsen en kleine bewegingen tijdens de dag. Bron: concepts.md ‘NEAT’, ‘BMR’ en ‘TEF’; 00:51-02:25.'),
  ('module-02', 2, 'Hoe moet een coach de uitkomst van Harris-Benedict met activiteitsfactor gebruiken?', jsonb_build_array('Als een startschatting die aan het gewichtsverloop en de context wordt getoetst.', 'Als een exacte onderhoudswaarde die voor de hele begeleiding vastligt.', 'Als een vervanging voor het opvolgen van inname en lichaamsgewicht.', 'Als een berekening die alleen bij wedstrijdatleten bruikbaar is.'), 'Als een startschatting die aan het gewichtsverloop en de context wordt getoetst.', 'De formule schat BMR en daarna TDEE, maar de module benadrukt dat de praktijk kan afwijken en bijsturing nodig blijft. Bron: learning-objectives.md LO3-4; concepts.md ‘Harris Benedict formule’; 09:03-16:25.'),
  ('module-02', 3, 'Een berekening plaatst een cliënt in een deficit, maar het gemiddelde gewicht verandert niet. Welke volgende stap sluit het best aan bij de module?', jsonb_build_array('Het berekende getal behouden omdat formules betrouwbaarder zijn dan de weegschaal.', 'Onmiddellijk alle koolhydraten schrappen zonder de totale inname te bekijken.', 'Het doel wijzigen van vetverlies naar spieropbouw zonder overleg.', 'De praktijkrespons en context beoordelen en de calorie-inname zo nodig bijsturen.'), 'De praktijkrespons en context beoordelen en de calorie-inname zo nodig bijsturen.', 'Het berekende target is een startpunt; het effect op de weegschaal en de context bepalen of het feitelijke deficit voldoende is. Bron: learning-objectives.md LO4; lessons.md les 3; 13:08-16:25.'),
  ('module-02', 4, 'Een cliënt traint drie keer per week maar beweegt op werkdagen nauwelijks. Welke interventie volgt het accent van de module het meest direct?', jsonb_build_array('Alle aandacht richten op langere krachttrainingen en de beperkte beweging buiten sport negeren.', 'Dagelijkse stappen en kleine bewegingsmomenten verhogen naast de bestaande training.', 'De eiwitinname verlagen om het energieverbruik te verhogen.', 'TEF vervangen door een extra wekelijkse sportsessie.'), 'Dagelijkse stappen en kleine bewegingsmomenten verhogen naast de bestaande training.', 'De module benadrukt NEAT omdat dagelijkse beweging een belangrijke component van het totale verbruik is en sport slechts een deel vormt. Bron: learning-objectives.md LO1; concepts.md ‘NEAT’; 01:34-03:35.'),
  ('module-02', 5, 'Een cliënt volgt thuis nauwkeurig een voedingsschema, maar kan dit tijdens een reis niet wegen of tracken. Welke tijdelijke aanpak noemt de module passend?', jsonb_build_array('Het traject pauzeren tot exact wegen opnieuw mogelijk is.', 'De cliënt zonder enige structuur laten eten omdat tracking ontbreekt.', 'Werken met richtlijnen of swaps die in de reissituatie uitvoerbaar zijn.', 'Het normale schema behouden en afwijkingen als gebrek aan eerlijkheid behandelen.'), 'Werken met richtlijnen of swaps die in de reissituatie uitvoerbaar zijn.', 'De module onderscheidt schema, tracking, richtlijnen en swaps en noemt richtlijnen bruikbaar wanneer reizen exact volgen moeilijk maakt. Bron: learning-objectives.md LO5; concepts.md ‘Voedingsstrategie’; 16:25-19:13.'),
  ('module-02', 6, 'Een coach heeft het caloriedoel bepaald en bouwt nu de macroverdeling op. Welke controle sluit het best aan bij de module?', jsonb_build_array('Alle calorieën eerst aan koolhydraten toewijzen en de rest gelijk verdelen.', 'Alleen percentages gebruiken; gram per kilogram hoeft niet gecontroleerd te worden.', 'Vetten zo laag mogelijk zetten zodat meer calorieën naar proteïne kunnen.', 'Voldoende proteïne en vet bewaken en koolhydraten afstemmen op doel en activiteit.'), 'Voldoende proteïne en vet bewaken en koolhydraten afstemmen op doel en activiteit.', 'Proteïne en vet krijgen een functionele ondergrens/prioriteit; koolhydraten variëren met doel en activiteit, en gram per kilogram blijft een controle naast percentages. Bron: concepts.md ‘Proteïnen’, ‘Vetten’, ‘Koolhydraten’ en ‘Macroverdeling’; 03:35-08:43 en 19:57-21:59.'),
  ('module-02', 7, 'Twee cliënten willen vet verliezen, maar één heeft een veel zwaardere werk- en trainingsweek. Hoe past de coach deficitlogica volgens de module toe?', jsonb_build_array('Voor beiden hetzelfde maximale percentage gebruiken om vergelijking mogelijk te maken.', 'Het percentage afstemmen op doel en levensstijl en daarna de praktische respons opvolgen.', 'Alleen de actiefste cliënt een surplus geven omdat die meer verbruikt.', 'Geen caloriedoel gebruiken zolang beide cliënten een ander activiteitsniveau hebben.'), 'Het percentage afstemmen op doel en levensstijl en daarna de praktische respons opvolgen.', 'De grootte van deficit of surplus hangt af van doel en levensstijl en moet via de praktijkrespons worden geëvalueerd. Bron: concepts.md ‘Deficit en surplus’; lessons.md les 3; 09:03-16:25.'),
  ('module-02', 8, 'Een cliënt zegt het berekende caloriedoel exact te volgen, maar het verwachte gewichtsverloop blijft uit. Welke conclusie is het meest verantwoord binnen de module?', jsonb_build_array('De energiebalans is voor deze cliënt niet van toepassing.', 'De Harris-Benedictformule bewijst dat de weegschaal onbetrouwbaar is.', 'De theoretische schatting of de feitelijke uitvoering kan afwijken; opvolging moet bepalen wat wordt aangepast.', 'De macropercentages moeten gelijk blijven en alleen het aantal maaltijden moet stijgen.'), 'De theoretische schatting of de feitelijke uitvoering kan afwijken; opvolging moet bepalen wat wordt aangepast.', 'De module presenteert berekening als startpunt en vraagt eerlijkheid, context en schaalrespons mee te nemen voordat targets worden aangepast. Bron: learning-objectives.md LO4; lessons.md les 3-4; 13:08-19:13.'),
  ('module-02', 9, 'Een coach kiest voor iedere cliënt standaard een volledig uitgeschreven voedingsschema omdat dit maximale controle geeft. Wat ontbreekt in die redenering?', jsonb_build_array('Een schema bevat nooit calorie- of macro-informatie.', 'Tracking is volgens de module altijd nauwkeuriger dan ieder schema.', 'Richtlijnen mogen alleen bij een surplus worden gebruikt.', 'De strategie moet ook passen bij eerlijkheid, haalbaarheid en context van de cliënt.'), 'De strategie moet ook passen bij eerlijkheid, haalbaarheid en context van de cliënt.', 'Controle is een voordeel van een schema, maar de module biedt meerdere strategieën en maakt geschiktheid afhankelijk van de persoon en situatie. Bron: concepts.md ‘Voedingsstrategie’; 16:25-19:13.'),
  ('module-02', 10, 'Een macroverdeling telt exact op tot 100%, maar levert voor de cliënt weinig proteïne en zeer weinig vet. Welke beoordeling past bij de module?', jsonb_build_array('De verdeling is onvoldoende beoordeeld; percentages moeten ook aan gram per kilogram en functies worden getoetst.', 'De verdeling is correct omdat iedere som van 100% nutritioneel in balans is.', 'De verdeling is alleen fout wanneer koolhydraten minder dan de helft innemen.', 'De verdeling wordt correct zodra het aantal eetmomenten wordt verdubbeld.'), 'De verdeling is onvoldoende beoordeeld; percentages moeten ook aan gram per kilogram en functies worden getoetst.', 'De module noemt percentages zoals 30/40/30, maar vraagt daarnaast proteïne en vet in gram per kilogram en hun functies te bewaken. Bron: learning-objectives.md LO5; concepts.md ‘Macroverdeling’; 19:57-21:59.'),
  ('module-03', 1, 'Waarom laat de module een coach eerst een businessblueprint opbouwen?', jsonb_build_array('Om ideeën, sterktes, doelgroep, aanbod en acties in één werkbare structuur te verbinden.', 'Om een definitief merk- en businessplan vast te leggen dat tijdens de latere groei niet meer mag veranderen.', 'Om de nood aan echte gesprekken en markfeedback volledig weg te nemen.', 'Om uitsluitend prijzen te vergelijken met die van andere coaches.'), 'Om ideeën, sterktes, doelgroep, aanbod en acties in één werkbare structuur te verbinden.', 'De blueprint brengt de bouwstenen van de business samen zodat kennis en passie kunnen worden omgezet in gerichte keuzes en acties. Bron: learning-objectives.md LO1; lessons.md les 1; 00:00-03:23.'),
  ('module-03', 2, 'Welke omschrijving van personal brand sluit het best aan bij de module?', jsonb_build_array('De vaste combinatie van logo, kleuren, lettertypes en visuele templates die op alle sociale media terugkomt.', 'Het aantal volgers dat een coach via consistente posts verzamelt.', 'Wat mensen voelen, denken en verwachten door je waarden, verhaal, energie en communicatie.', 'De lijst van diensten en prijzen die op een website staat.'), 'Wat mensen voelen, denken en verwachten door je waarden, verhaal, energie en communicatie.', 'De module stelt expliciet dat personal brand breder is dan logo of feed en gaat over de verwachting die jouw aanwezigheid oproept. Bron: concepts.md ‘Personal brand’; lessons.md les 2; 03:23-11:24.'),
  ('module-03', 3, 'Een coach post dagelijks over willekeurige onderwerpen en vindt moeilijk een herkenbare lijn. Welke ingreep past bij de module?', jsonb_build_array('Op meer platforms nog vaker posten, zodat de hogere frequentie het ontbreken van een inhoudelijke lijn compenseert.', 'Terugkerende contentthema’s kiezen die zijn sterktes, doelgroep en transformaties zichtbaar maken.', 'Alleen prijspromoties posten zodat het aanbod centraal staat.', 'Stoppen met persoonlijke communicatie en alleen oefeningen tonen.'), 'Terugkerende contentthema’s kiezen die zijn sterktes, doelgroep en transformaties zichtbaar maken.', 'Content buckets zijn terugkerende thema’s die consistente zichtbaarheid verbinden met personal brand en positionering. Bron: learning-objectives.md LO2; concepts.md ‘Content buckets’; 03:23-11:24.'),
  ('module-03', 4, 'Een coach wil groeien maar krijgt weinig energie van veel vaste één-op-éénuren. Welke vraag moet volgens de module vóór verdere groei centraal staan?', jsonb_build_array('Welke cliënt en welk begeleidingsmodel passen bij de werkweek die ik werkelijk wil bouwen?', 'Hoe kan ik zoveel mogelijk verschillende cliënttypes tegelijk aannemen zonder mijn werkweek vooraf te begrenzen?', 'Welke prijs kan ik kopiëren zonder mijn eigen capaciteit te berekenen?', 'Hoe kan ik iedere aanvraag accepteren zonder selectie of pakketkeuze?'), 'Welke cliënt en welk begeleidingsmodel passen bij de werkweek die ik werkelijk wil bouwen?', 'De module waarschuwt dat groei op papier een business kan opleveren die niet bij de coach past; cliënttype en model moeten aansluiten op de gewenste werkweek. Bron: learning-objectives.md LO3; lessons.md les 3; 11:24-16:49.'),
  ('module-03', 5, 'Een prospect hoort alleen: ‘Ik doe coaching en maak schema’s.’ Welke verbetering volgt de module?', jsonb_build_array('Meer vaktermen toevoegen zonder het traject concreter te maken.', 'De prijs weglaten en vijf vergelijkbare opties uitgebreid naast elkaar zetten zodat de prospect zelf alle verschillen afweegt.', 'Wachten tot de prospect zelf bedenkt welke begeleiding mogelijk is.', 'Een beperkt aantal pakketten tonen met doelgroep, inhoud en passend probleem per traject.'), 'Een beperkt aantal pakketten tonen met doelgroep, inhoud en passend probleem per traject.', 'De module adviseert een beperkt aantal duidelijke pakketten zodat de cliënt begrijpt wat hij krijgt en welke optie bij zijn situatie past. Bron: concepts.md ‘Pakket en aanbod’; lessons.md les 4; 16:50-22:23.'),
  ('module-03', 6, 'Een prospect vraagt meteen naar de prijs, maar doel, context en pijnpunten zijn nog onbekend. Welke reactie past bij de salesflow?', jsonb_build_array('Onmiddellijk de goedkoopste prijs sturen om weerstand te voorkomen.', 'Eerst gerichte vragen stellen en daarna pas het passende pakket en de investering kaderen.', 'Alle beschikbare pakketten sturen en de prospect zelf laten filteren.', 'Het gesprek beëindigen omdat een prijsvraag gebrek aan commitment toont.'), 'Eerst gerichte vragen stellen en daarna pas het passende pakket en de investering kaderen.', 'Information Gathering gaat vooraf aan de pitch zodat de coach doelen, pijn, context en mogelijke bezwaren begrijpt en passend kan adviseren. Bron: learning-objectives.md LO4; concepts.md ‘Information Gathering’; 22:23-33:27.'),
  ('module-03', 7, 'Na een grondige intake zijn twee pakketten mogelijk, maar één sluit duidelijk beter aan. Wat doet de coach volgens de module?', jsonb_build_array('Alle vijf mogelijke opties opsommen en geen richting geven.', 'Altijd het duurste pakket adviseren, los van de informatie.', 'Het best passende pakket aanbevelen en uitleggen waarom het aansluit.', 'Alleen de prijs noemen en de inhoud pas na betaling bespreken.'), 'Het best passende pakket aanbevelen en uitleggen waarom het aansluit.', 'De coach is de filter en gebruikt de verzamelde informatie om niet zomaar opties te dumpen, maar een passend pakket voor te stellen. Bron: lessons.md les 6; 33:27-38:56.'),
  ('module-03', 8, 'Een coach geeft na twee minuten een uitgebreide pitch. De prospect zegt: ‘Ik moet erover nadenken.’ Welke eerdere stap is waarschijnlijk onvoldoende uitgevoerd volgens de module?', jsonb_build_array('De coach heeft te weinig content buckets gebruikt tijdens het gesprek.', 'De coach heeft zijn juridische ondernemingsvorm niet toegelicht.', 'De coach heeft te weinig pakketten tegelijk aangeboden.', 'De coach heeft doelen, pijnpunten, context en twijfel onvoldoende onderzocht.'), 'De coach heeft doelen, pijnpunten, context en twijfel onvoldoende onderzocht.', 'Een sterke pitch volgt op Information Gathering; zonder die informatie mist de pitch aansluiting en blijven bezwaren of onzekerheid onontdekt. Bron: learning-objectives.md LO4-5; lessons.md les 5; 22:23-33:27.'),
  ('module-03', 9, 'Een prospect zegt dat het traject duur voelt. Welke reactie past het best bij de module?', jsonb_build_array('Het bezwaar negeren en de betalingslink opnieuw sturen.', 'De prospect overtuigen dat prijs nooit een geldig bezwaar is.', 'Onderzoeken welke twijfel of zekerheid achter het bezwaar zit en daarop reageren.', 'Onmiddellijk korting geven voordat duidelijk is wat de twijfel betekent.'), 'Onderzoeken welke twijfel of zekerheid achter het bezwaar zit en daarop reageren.', 'De module behandelt bezwaren als twijfels die om meer begrip en zekerheid kunnen vragen; eerst onderzoeken voorkomt een defensieve of automatische reactie. Bron: learning-objectives.md LO5; concepts.md ‘Bezwaren’; 25:16-38:56.'),
  ('module-03', 10, 'Een coach trekt veel vrijblijvende aanvragen aan die zelden bij zijn pakketten passen. Welke combinatie pakt volgens de module het fundament het best aan?', jsonb_build_array('De doelgroep breder maken en vaker dezelfde generieke pitch gebruiken.', 'Alle content vervangen door kortingen en de intake inkorten.', 'Meer pakketten toevoegen zodat voor iedereen iets beschikbaar is.', 'Sterktes en ideale cliënt aanscherpen, content daarop richten en vóór de pitch beter kwalificeren.'), 'Sterktes en ideale cliënt aanscherpen, content daarop richten en vóór de pitch beter kwalificeren.', 'De module verbindt blueprint, personal brand, ideale cliënt, duidelijk aanbod en Information Gathering tot één lijn; mismatch ontstaat vaak vóór de closing. Bron: learning-objectives.md LO1-4; lessons.md les 1-5; 00:00-33:27.'),
  ('module-04', 1, 'Wanneer gaat begeleiding volgens de module verder dan alleen personal training?', jsonb_build_array('Wanneer iedere sessie meer oefeningen, technische correcties en trainingsprikkels bevat dan de voorgaande sessie.', 'Wanneer de coach training, voeding, gedrag, doelen en relatie in samenhang begeleidt.', 'Wanneer de coach uitsluitend buiten de trainingsuren contact opneemt.', 'Wanneer technische correcties worden vervangen door motiverende slogans.'), 'Wanneer de coach training, voeding, gedrag, doelen en relatie in samenhang begeleidt.', 'Coaching creëert blijvende meerwaarde door meer dan de uitvoering van een sessie of schema te begeleiden. Bron: learning-objectives.md LO1; concepts.md ‘Coach versus personal trainer’; 00:22-00:46.'),
  ('module-04', 2, 'Welke uitspraak beschrijft het verschil tussen een doel en een commitment het best?', jsonb_build_array('Een doel beschrijft de richting; een commitment vertaalt die richting naar een besluit en concrete actie.', 'Een doel is de bindende afspraak met de coach; een commitment blijft een persoonlijke wens die nog geen concrete actie vereist.', 'Een commitment komt uitsluitend van de coach; een doel uitsluitend van de cliënt.', 'Beide betekenen inhoudelijk hetzelfde, maar commitment klinkt in een coachingsgesprek motiverender.'), 'Een doel beschrijft de richting; een commitment vertaalt die richting naar een besluit en concrete actie.', 'De module gebruikt het doel als richtpunt en commitment als besluit waarop gedrag en integriteit kunnen worden opgevolgd. Bron: concepts.md ‘Commitment versus doel’; 03:34-04:11.'),
  ('module-04', 3, 'Een cliënt startte voor vetverlies, maar noemt na maanden vooral stress, slaap en energie als zorgen. Welke coachactie past het best?', jsonb_build_array('Het oorspronkelijke vetverliesdoel en de volledige intake-aanpak behouden omdat doelen na de start van een traject vaststaan.', 'Alleen het trainingsvolume verhogen zodat vetverlies weer centraal komt.', 'Het traject afsluiten omdat de cliënt niet langer consistent is.', 'Opnieuw vragen wat het huidige doel is, waarom dit telt en de aanpak daarop afstemmen.'), 'Opnieuw vragen wat het huidige doel is, waarom dit telt en de aanpak daarop afstemmen.', 'Doelen en motivaties zijn dynamisch; de coach moet ze doorheen het traject opnieuw bevragen om relevant te blijven. Bron: learning-objectives.md LO2; concepts.md ‘Dynamische doelen’; 03:04-06:20.'),
  ('module-04', 4, 'Een cliënt wil minder alcohol drinken en vraagt om opvolging. Welke aanpak weerspiegelt accountability uit de module?', jsonb_build_array('Dagelijks alle keuzes controleren, iedere afwijking registreren en daar onmiddellijk een vaste consequentie aan koppelen.', 'De keuze volledig loslaten omdat verantwoordelijkheid alleen bij de cliënt ligt.', 'Een duidelijke commitment afspreken en er als betekenisvolle relatie op terugkomen.', 'Alleen extra voedingskennis sturen zonder het gedrag te bespreken.'), 'Een duidelijke commitment afspreken en er als betekenisvolle relatie op terugkomen.', 'Accountability betekent dat de cliënt verantwoording wíl afleggen binnen de relatie; dit wordt gedragen door commitment, niet door politiewerk. Bron: concepts.md ‘Accountability’; lessons.md les 3; 06:20-10:08.'),
  ('module-04', 5, 'Een nieuwe cliënt reageert sterk op uitleg en wil begrijpen waarom oefeningen werken, maar haakt af bij losse humor. Wat doet de coach?', jsonb_build_array('Meer humor gebruiken zodat de cliënt geleidelijk aan de vaste connectiestijl van de coach went.', 'De uitleg beperken en alleen het schema laten spreken.', 'Iedere sessie dezelfde connectiestijl gebruiken als bij andere cliënten.', 'Via kennis en relevante uitleg verbinden en blijven observeren wat respons geeft.'), 'Via kennis en relevante uitleg verbinden en blijven observeren wat respons geeft.', 'Connectiestijl verschilt per cliënt en kan onder meer via kennis, humor, interesses of emotionele steun verlopen. Bron: learning-objectives.md LO4; concepts.md ‘Connectiestijl’; 10:08-13:01.'),
  ('module-04', 6, 'Een cliënt verliest bij een squat het gevoel van druk over de volledige voet. Welke cue past bij de module?', jsonb_build_array('Vraag de cliënt de druk over de volledige voet te voelen en de grond weg te duwen.', 'Noem alleen de anatomische naam van alle betrokken spieren.', 'Verhoog onmiddellijk het gewicht zodat de fout duidelijker wordt.', 'Wacht tot na de sessie en stuur uitsluitend een geschreven schema.'), 'Vraag de cliënt de druk over de volledige voet te voelen en de grond weg te duwen.', 'De module gebruikt proprioceptieve en metaforische cues om techniek te vertalen naar wat een cliënt moet voelen en controleren. Bron: concepts.md ‘Cues’; lessons.md les 5; 13:02-16:00.'),
  ('module-04', 7, 'Een cliënt komt om 6.00 uur vermoeid binnen na een slechte nacht. Welke houding volgt de thermostaatmetafoor?', jsonb_build_array('De lage energie spiegelen zodat de cliënt zich begrepen voelt.', 'Voorbereid de sfeer en standaard dragen, terwijl je de toestand van de cliënt blijft meenemen.', 'De sessie zonder gesprek exact uitvoeren zoals op papier staat.', 'De cliënt verantwoordelijk maken voor de energie van de volledige sessie.'), 'Voorbereid de sfeer en standaard dragen, terwijl je de toestand van de cliënt blijft meenemen.', 'De coach bepaalt als thermostaat de sfeer, energie en professionele standaard; dat sluit observeren en afstemmen niet uit. Bron: concepts.md ‘Coach als thermostaat’; 16:23-16:53.'),
  ('module-04', 8, 'Een cliënt voert een afgesproken plan herhaaldelijk niet uit. Welke eerste analyse past het best bij de module?', jsonb_build_array('De cliënt mist discipline; hetzelfde plan moet strenger worden opgelegd.', 'Het doel zonder overleg schrappen omdat de uitvoering herhaaldelijk ontbreekt.', 'Onderzoek of doel, bereidheid, ondersteuning en plan nog passen vóór je alleen de cliënt verantwoordelijk stelt.', 'Technische kennis ontbreekt altijd en moet eerst met meer informatie worden aangevuld.'), 'Onderzoek of doel, bereidheid, ondersteuning en plan nog passen vóór je alleen de cliënt verantwoordelijk stelt.', 'De module vraagt de coach eerst te onderzoeken hoe de aanpak, ondersteuning en aansluiting beter kunnen voordat falen volledig bij de cliënt wordt gelegd. Bron: learning-objectives.md LO5; lessons.md les 6; 17:17-19:59.'),
  ('module-04', 9, 'Een coach maakt perfecte schema’s en corrigeert techniek, maar bespreekt nooit motivatie, commitments of gedrag. Op welk probleem wijst de module?', jsonb_build_array('De coach gebruikt te weinig verschillende oefenvarianten.', 'De coach blijft vooral op kennisoverdracht en feedback, zonder diepere accountability en connectie.', 'De coach bouwt te veel authentieke connectie en te weinig afstand.', 'De coach behandelt de cliënt al op het diepste niveau van coaching.'), 'De coach blijft vooral op kennisoverdracht en feedback, zonder diepere accountability en connectie.', 'Schema’s en techniek zijn waardevol, maar de levels lopen verder via accountability, commitment en connecting state. Bron: learning-objectives.md LO3; concepts.md ‘Levels van coaching’; 06:20-10:08.'),
  ('module-04', 10, 'Tijdens een sessie blijkt slaap de bottleneck achter terugkerende uitval, terwijl de techniek goed is. Welke keuze past bij impactgericht leiderschap?', jsonb_build_array('Toch extra technische cues geven omdat de sessie daarvoor betaald is.', 'Een extra set toevoegen om de beschikbare tijd volledig te benutten.', 'Het onderwerp vermijden omdat slaap buiten training valt.', 'De slaapbottleneck gericht bevragen en een relevante commitment helpen formuleren.'), 'De slaapbottleneck gericht bevragen en een relevante commitment helpen formuleren.', 'De module vraagt per sessie naar de meest waardevolle interventie; die kan een vraag of initiatief rond een leefstijl-bottleneck zijn in plaats van meer training. Bron: lessons.md les 7; 19:59-25:06.'),
  ('module-05', 1, 'Waarom behandelt de module offer creation, lead generation, appointment setting en sales mastery in deze volgorde?', jsonb_build_array('Omdat elke stap de noodzakelijke input voor de volgende stap oplevert.', 'Omdat de vier stappen administratief verschillen en in de praktijk los van elkaar uitgevoerd kunnen worden.', 'Omdat sales mastery moet starten voordat een aanbod bestaat.', 'Omdat lead generation pas zinvol is nadat alle calls zijn gevoerd.'), 'Omdat elke stap de noodzakelijke input voor de volgende stap oplevert.', 'Een sterk aanbod maakt gerichte leads mogelijk, gesprekken zetten leads om naar calls en sales sluit gekwalificeerde calls; de stappen bouwen op elkaar voort. Bron: learning-objectives.md LO1; concepts.md ‘Acquisitiesysteem’; 00:21-02:29.'),
  ('module-05', 2, 'Welke eigenschap maakt gratis content volgens de module tot een sterke lead magnet?', jsonb_build_array('Ze beschrijft zoveel mogelijk problemen van de volledige doelgroep zonder één concreet resultaat volledig af te ronden.', 'Ze lost een klein specifiek probleem volledig genoeg op om waarde te laten ervaren.', 'Ze geeft alleen een kortingscode voor het betaalde traject.', 'Ze bevat de volledige betaalde begeleiding zonder volgende stap.'), 'Ze lost een klein specifiek probleem volledig genoeg op om waarde te laten ervaren.', 'Een lead magnet is een complete oplossing voor een klein probleem en vormt een waardevolle eerste shift richting het betaalde aanbod. Bron: learning-objectives.md LO3; concepts.md ‘Lead magnet’; 05:29-14:05.'),
  ('module-05', 3, 'Een coach biedt ‘fitnesscoaching voor iedereen’ aan en is nergens de voor de hand liggende keuze. Wat is de meest directe verbetering?', jsonb_build_array('De prijs verlagen zodat het algemene aanbod toch opvalt.', 'Meer methodes toevoegen zonder de brede doelgroep of de algemene uitkomst te wijzigen.', 'Een specifieke doelgroep, context, uitkomst en methode in het aanbod verbinden.', 'Het aanbod behouden en alleen vaker dezelfde boodschap posten.'), 'Een specifieke doelgroep, context, uitkomst en methode in het aanbod verbinden.', 'Offer creation en Blue Ocean vragen specificiteit: voor wie, welk resultaat en via welke methode, zodat de coach minder vervangbaar wordt. Bron: learning-objectives.md LO2; concepts.md ‘Offer Creation’, ‘Niche’ en ‘Blue Ocean’; 02:29-05:29.'),
  ('module-05', 4, 'Een coach voor drukke ondernemers verkoopt duurzame voedingscoaching. Welke lead magnet sluit het best aan bij de modulelogica?', jsonb_build_array('Een algemene verzameling met honderd fitness- en voedingsweetjes die voor iedere mogelijke doelgroep bedoeld is.', 'Een gratis kennismaking zonder concrete uitkomst of voorbereiding.', 'Een volledig willekeurig trainingsschema voor gevorderde bodybuilders.', 'Een korte praktische oplossing voor één voedingsprobleem van drukke ondernemers die naar verdere coaching opent.'), 'Een korte praktische oplossing voor één voedingsprobleem van drukke ondernemers die naar verdere coaching opent.', 'De lead magnet moet een klein relevant probleem van dezelfde niche oplossen en de stap naar het betaalde aanbod logisch kleiner maken. Bron: learning-objectives.md LO2-3; lessons.md les 2-3; 02:29-14:05.'),
  ('module-05', 5, 'Een startende coach heeft een helder aanbod maar nog geen leads of advertentiedata. Welke aanpak benadrukt de module eerst?', jsonb_build_array('Organisch zichtbaar worden, relevante mensen benaderen en consequent opvolgen.', 'Wachten tot de niche vanzelf via zoekmachines binnenkomt.', 'Direct in advertenties investeren en persoonlijke gesprekken en opvolging voorlopig uitstellen.', 'Het aanbod opnieuw bouwen zonder het ooit met mensen te testen.'), 'Organisch zichtbaar worden, relevante mensen benaderen en consequent opvolgen.', 'Voor de eerste klanten legt de module nadruk op organische posts, outreach, DM’s en opvolging voordat advertenties centraal staan. Bron: concepts.md ‘Lead generation’; lessons.md les 3; 05:29-14:05.'),
  ('module-05', 6, 'Een lead reageert op een post en vertelt kort over een probleem. Wat is volgens de module de beste volgende stap?', jsonb_build_array('Meteen het volledige aanbod en de prijs in één bericht sturen.', 'Een open vraag stellen, luisteren en de huidige en gewenste situatie verder begrijpen.', 'Direct een calllink sturen zonder te weten of de persoon past.', 'Alleen extra gratis informatie sturen en nooit richting gesprek bewegen.'), 'Een open vraag stellen, luisteren en de huidige en gewenste situatie verder begrijpen.', 'Appointment setting bouwt eerst verbinding en context op via open vragen en stilte, en beweegt daarna op het juiste moment naar een call. Bron: learning-objectives.md LO4; lessons.md les 4; 14:05-18:01.'),
  ('module-05', 7, 'In een call kent de coach de huidige situatie en het gewenste resultaat. Welke stap maakt de nood aan begeleiding vervolgens concreet?', jsonb_build_array('De prijs noemen voordat de obstakels zijn besproken.', 'De lead opnieuw dezelfde beginsituatie laten beschrijven.', 'Het verschil en de obstakels tussen huidige en gewenste situatie onderzoeken.', 'Onmiddellijk bezwaren weerleggen die nog niet zijn uitgesproken.'), 'Het verschil en de obstakels tussen huidige en gewenste situatie onderzoeken.', 'De gap is het verschil tussen de huidige en gewenste situatie; dit maakt helder wat ontbreekt voordat het medicijn of de pitch wordt aangeboden. Bron: learning-objectives.md LO5; concepts.md ‘Gap’; 15:54-22:11.'),
  ('module-05', 8, 'Een coach stuurt elke nieuwe volger direct een aanbod en calllink. Er komen veel korte afwijzingen. Welke systeemsfout verklaart dit het best?', jsonb_build_array('De coach gebruikt te veel open vragen vóór de call.', 'De coach heeft de investering nog niet als prijs benoemd.', 'De coach lost in DM al te veel kleine problemen volledig op.', 'De coach slaat verbinding en kwalificatie over en probeert appointment setting als closing te gebruiken.'), 'De coach slaat verbinding en kwalificatie over en probeert appointment setting als closing te gebruiken.', 'De module waarschuwt voor te vroeg, hard en snel pitchen; DM is bedoeld om vertrouwen en kwalificatie op te bouwen richting call. Bron: learning-objectives.md LO4; lessons.md les 4; 14:05-18:01.'),
  ('module-05', 9, 'Twee pitches zijn inhoudelijk correct. Welke pitch past beter bij identity selling?', jsonb_build_array('‘Je krijgt twaalf schema’s, check-ins en toegang tot video’s.’', '‘Je krijgt dezelfde onderdelen als iedere andere cliënt in dit pakket.’', '‘We koppelen de begeleiding aan de versie van jezelf die je wilt worden en de kloof die je nu tegenhoudt.’', '‘We bespreken vooral de technische functies en vermijden je gewenste situatie.’'), '‘We koppelen de begeleiding aan de versie van jezelf die je wilt worden en de kloof die je nu tegenhoudt.’', 'Identity selling verbindt het aanbod met de gewenste versie van de prospect en met pijn, droom en gap, niet alleen met deliverables. Bron: concepts.md ‘Identity selling’; lessons.md les 5; 21:43-22:11.'),
  ('module-05', 10, 'Een coach noemt de investering en begint de stilte meteen op te vullen met korting en extra uitleg. Welke correctie volgt de module?', jsonb_build_array('De investering opnieuw als kost benoemen en sneller praten.', 'De call terugbrengen naar lead generation en nieuwe posts bespreken.', 'Een tweede pakket toevoegen voordat de prospect reageert.', 'De investering rustig laten staan, zwijgen en de prospect ruimte geven om te antwoorden.'), 'De investering rustig laten staan, zwijgen en de prospect ruimte geven om te antwoorden.', 'De module noemt de prijs een investering en vraagt de coach daarna de stilte niet meteen te breken, zodat een echte reactie en beslissing kan ontstaan. Bron: concepts.md ‘Investeringstaal’; 25:10-25:40.');

-- Keep historical questions for attempt integrity, but remove them from new attempts.
-- Move their order indexes out of the active 1-10 range because the legacy schema
-- enforces uniqueness across active and inactive questions alike.
update public.exam_questions question set is_active = false, order_index = -question.id::integer, updated_at = now()
where question.exam_id in (
  select exam.id
  from deep_exam_targets target
  join public.exams exam on exam.module_id = target.module_id
);

-- In-progress attempts contain immutable question snapshots. They must be
-- restarted when the underlying question bank is replaced; submitted attempts
-- and results remain untouched. Child snapshots cascade with the attempt.
delete from public.exam_attempts attempt
where attempt.status = 'in_progress'
  and attempt.exam_id in (
    select exam.id
    from deep_exam_targets target
    join public.exams exam on exam.module_id = target.module_id
  );

insert into public.exam_questions (exam_id, module_id, question, question_text, explanation, options, correct_answer, order_index, is_active)
select exam.id, target.module_id, bank.question_text, bank.question_text, bank.explanation, bank.options, bank.correct_answer, bank.order_index, true
from deep_exam_bank bank join deep_exam_targets target using (module_key) join public.exams exam on exam.module_id = target.module_id
where not exists (select 1 from public.exam_questions existing where existing.module_id = target.module_id and existing.question_text = bank.question_text and existing.deleted_at is null);

update public.exam_questions question set question = bank.question_text, explanation = bank.explanation, options = bank.options, correct_answer = bank.correct_answer, order_index = bank.order_index, is_active = true, deleted_at = null, updated_at = now()
from deep_exam_bank bank join deep_exam_targets target using (module_key)
where question.module_id = target.module_id and question.question_text = bank.question_text;

insert into public.exam_answer_options (question_id, option_text, is_correct, order_index)
select question.id, option.value, option.value = bank.correct_answer, option.ordinality::integer - 1
from deep_exam_bank bank join deep_exam_targets target using (module_key)
join public.exam_questions question on question.module_id = target.module_id and question.question_text = bank.question_text
cross join lateral jsonb_array_elements_text(bank.options) with ordinality option(value, ordinality)
where not exists (select 1 from public.exam_answer_options existing where existing.question_id = question.id and existing.option_text = option.value);

do $$ declare invalid text; begin
  select string_agg(format('%s vraag %s', check_row.module_key, check_row.order_index), ', ' order by check_row.module_key, check_row.order_index) into invalid
  from (
    select target.module_key, bank.order_index
    from deep_exam_bank bank join deep_exam_targets target using (module_key)
    join public.exam_questions question on question.module_id = target.module_id and question.question_text = bank.question_text
    left join public.exam_answer_options option on option.question_id = question.id
    group by target.module_key, bank.order_index, question.id
    having count(option.id) <> 4 or count(option.id) filter (where option.is_correct) <> 1
  ) check_row;
  if invalid is not null then raise exception 'Ongeldige vragen: %', invalid; end if;
end $$;

do $$ declare invalid_modules text; begin
  select string_agg(check_row.module_key, ', ' order by check_row.module_key) into invalid_modules
  from (
    select target.module_key
    from deep_exam_targets target
    join public.exams exam on exam.module_id = target.module_id
    left join public.exam_questions question
      on question.exam_id = exam.id
     and question.is_active = true
     and question.deleted_at is null
    group by target.module_key
    having count(question.id) <> 10
       or count(distinct question.order_index) <> 10
       or min(question.order_index) <> 1
       or max(question.order_index) <> 10
  ) check_row;
  if invalid_modules is not null then
    raise exception 'Actieve vraagbank is niet exact 1-10 voor: %', invalid_modules;
  end if;
end $$;

commit;
